var LINERS=[
  {id:'corsa',name:'Corsa',tag:'Race-only precision. Exclusively for race and ultra-low-volume shells demanding maximum control.',w:2,p:5,vol:'Low',vols:['LV','Race','Race/LV'],issues:['control','heel'],ins:['low','medium'],ank:['low','medium'],cal:['low','medium'],feat:['Cork fill system','Race-specific construction','Maximum energy transfer','Precision narrow last'],why:"The Corsa is built exclusively for race and ultra-low-volume shells. The cork fill system locks your heel down and eliminates dead space for total power transfer. If you are in a race shell, this is your liner."},
  {id:'gft',name:'GFT',tag:'The precision all-rounder. Built for low-volume downhill, touring, and crossover shells.',w:3,p:4,vol:'Medium',vols:['MV','LV','MV-Wide'],issues:['heel','control'],ins:['low','medium','high'],ank:['low','medium','high'],cal:['low','medium'],feat:['Cork fill system','All-mountain performance','Balanced volume','Versatile fit'],why:"The GFT is the go-to ZipFit liner for low-volume downhill shells, touring boots, and crossover shells. The cork fill system delivers a precise custom fit that transforms energy transfer and heel hold whether you are carving on the resort or skinning into the backcountry."},
  {id:'espresso',name:'Espresso',tag:'Ultralight LV touring precision. Built for the lightest, most dedicated AT shells.',w:2,p:4,vol:'Low-Medium',vols:['LV','Race/LV'],issues:['heel','control'],ins:['low','medium'],ank:['low','medium'],cal:['low','medium'],feat:['Cork fill system','Ultralight touring construction','LV precision fit','Uphill and downhill performance'],why:"The Espresso is ZipFit's ultralight LV touring liner, built specifically for dedicated low-volume AT shells. The cork fill system delivers a locked-in, responsive fit that performs on the descent without weighing you down on the ascent."},
  {id:'gara_lv',name:'Gara LV',tag:'Warm performance for low-volume shells. For lean to average calves with lean/bony ankles who need warmth.',w:4,p:4,vol:'Low-Medium',vols:['LV','Race','Race/LV'],issues:['cold','heel','control'],ins:['low','medium'],ank:['low','medium'],cal:['low','medium'],feat:['Cork fill system','Enhanced insulation','Low-volume shell fit','Cold-weather performance'],why:"The Gara LV brings serious warmth to skiers in low-volume shells with lean to average calf volume. If cold feet have been holding you back, the Gara LV delivers cork precision and real insulation without compromising the locked-in fit you need for performance skiing."},
  {id:'gara_hv',name:'Gara HV',tag:'Warm performance for medium- to high-volume shells. For lean to average calves with fuller ankles who run cold.',w:4,p:4,vol:'Medium-High',vols:['HV','MV','MV-Wide'],issues:['cold','heel','control'],ins:['medium','high'],ank:['medium','high'],cal:['low','medium'],feat:['Cork fill system','Enhanced insulation','Higher-volume shell fit','Cold-weather performance'],why:"The Gara HV pairs ZipFit cork warmth with a higher-volume shell fit for skiers who run cold but have lean to average calf volume. You get the warmth you need on cold days without sacrificing the precise custom fit the cork system delivers."},
  {id:'freeride',name:'Freeride',tag:'The all-mountain comfort liner. Built for higher-volume shells and fuller lower legs.',w:4,p:3,vol:'Medium-High',vols:['HV','MV','MV-Wide'],issues:['cold','heel'],ins:['medium','high'],ank:['medium','high'],cal:['medium','high'],feat:['Cork fill system','Fuller calf fit','Higher-volume shell fit','Great for all levels'],why:"The Freeride is the go-to liner for skiers in higher-volume shells who have a fuller or muscular lower leg. The higher-volume construction accommodates larger calf volume that other liners can struggle with, while the cork fill system still delivers a custom fit. A great choice for beginner and intermediate skiers who want meaningful comfort and performance improvement."},
  {id:'workhorse',name:'Workhorse',tag:'Maximum warmth for higher-volume shells. Built for experts who live in their boots.',w:5,p:4,vol:'High',vols:['HV','MV','MV-Wide'],issues:['cold','pain'],ins:['high'],ank:['high'],cal:['high'],feat:['Cork fill system','Maximum insulation','Expert-level performance','All-day warmth'],why:"The Workhorse is ZipFit's warmest US liner, built for expert skiers and boot industry professionals who spend their days on snow in higher-volume shells. Maximum insulation keeps you warm on the coldest days while the cork fill system ensures you never sacrifice performance for warmth."}
];
var FIT_PROBLEMS=[
  {v:'heel_lift',l:'Heel lift',d:'Your heel rises or shifts inside the boot when you flex forward or pressure the tongue — you can feel it lifting with each turn.',icon:'🦶',msg:'ZipFit liners address heel lift directly. The cork fill system molds to your exact heel geometry, eliminating the dead space that causes lift. Your bootfitter can also fine-tune the shell fit for a lasting solution.',link:'#heel-lift-solutions'},
  {v:'shin_bang',l:'Shin bang',d:'A sharp bruising pain on your shin that builds through the day, usually after hard or repeated flexion into the tongue of the boot.',icon:'🦵',msg:'Shin bang is usually caused by forward lean, buckle tension, or liner pack-out. A ZipFit liner reduces pack-out significantly, keeping your fit consistent. Your bootfitter can address forward lean and buckle setup.',link:'#shin-bang-solutions'},
  {v:'toe_bang',l:'Toe bang',d:'Your longest toe hits the front of the shell on steep terrain or when flexing hard — painful on long runs and descents.',icon:'💥',msg:'Toe bang is often a shell length or flex issue. A ZipFit liner helps by eliminating excess volume that lets the foot slide forward. Your bootfitter can evaluate shell length and forefoot fit.',link:'#toe-bang-solutions'},
  {v:'navicular_pain',l:'Navicular / instep pain',d:'Pressure or pain on the top of your foot or over the arch — usually from the boot tongue pressing on a high instep or prominent navicular bone.',icon:'↕️',msg:'Navicular and instep pain is almost always a volume mismatch — the shell is pressing directly on a high spot. A ZipFit liner redistributes pressure by molding around the navicular instead of pressing on it. For severe cases your bootfitter can also punch the shell directly over the bone.',link:'#navicular-pain-solutions'},
  {v:'cold_feet',l:'Cold feet',d:'Your feet go numb or painfully cold within an hour or two on the mountain, regardless of sock thickness or how tight you buckle.',icon:'🥶',msg:'Cold feet are often made worse by poor fit — a loose liner allows air circulation that chills your foot. ZipFit liners dramatically reduce this by sealing the foot with a custom cork mold. For extreme cold, your bootfitter can also discuss insulation options.',link:'#cold-feet-solutions'},
  {v:'wide_forefoot',l:'Wide forefoot pressure',d:'Pain, numbness, or a pinching sensation across the ball of your foot — often worse after an hour of skiing as your foot swells.',icon:'↔️',msg:'Forefoot pressure is typically a shell width issue rather than a liner issue. Your ZipFit liner will not add pressure here — in fact it reduces overall volume inconsistency. Your bootfitter can punch or grind the shell for lasting relief.',link:'#wide-forefoot-solutions'},
  {v:'ankle_bite',l:'Ankle bite',d:'Sharp pressure or bruising on one or both sides of your ankle — usually from a bony prominence pressing directly into the shell or cuff buckle.',icon:'🦴',msg:'Ankle bite is caused by bony prominences pressing against the shell or cuff. A ZipFit liner provides a custom cork interface that cushions these areas. Your bootfitter can also spot-punch the shell for direct relief.',link:'#ankle-bite-solutions'},
  {v:'none',l:'No major issues',d:'Your boots are generally comfortable and you ski without significant pain or distraction — you just want a better, more precise fit.',icon:'✓',msg:'Great — your ZipFit liner will build on that comfort by delivering a more precise, custom fit through the cork fill system. Expect better heel hold, improved energy transfer, and a fit that stays consistent all season.',link:null}
];

function svgFF(rx,col){return'<svg viewBox="0 0 80 68" fill="none"><ellipse cx="40" cy="48" rx="'+rx+'" ry="16" fill="rgba('+col+',.14)" stroke="rgba('+col+',.6)" stroke-width="1.5"/><ellipse cx="40" cy="20" rx="'+(rx-3)+'" ry="11" fill="rgba('+col+',.14)" stroke="rgba('+col+',.6)" stroke-width="1.5"/></svg>';}
function svgFF1(){return svgFF(10,'168,207,224');}function svgFF2(){return svgFF(15,'168,207,224');}function svgFF3(){return svgFF(21,'232,201,106');}function svgFF4(){return svgFF(28,'240,160,100');}
function svgArch(cy1,cy2,col){return'<svg viewBox="0 0 90 54" fill="none"><path d="M8 '+cy1+' Q24 '+cy2+' 48 '+(cy2-4)+' Q68 '+(cy2-8)+' 82 42" stroke="rgba('+col+',.55)" stroke-width="1.5" stroke-linecap="round"/><path d="M8 '+cy1+' Q10 '+(cy2-10)+' 18 '+(cy2-18)+' Q28 '+(cy2-28)+' 40 '+(cy2-30)+' Q55 '+(cy2-32)+' 66 '+(cy2-24)+' Q76 '+(cy2-16)+' 82 42Z" fill="rgba('+col+',.09)" stroke="rgba('+col+',.38)" stroke-width="1.3"/></svg>';}
function svgA1(){return svgArch(44,42,'168,207,224');}function svgA2(){return svgArch(44,32,'168,207,224');}function svgA3(){return svgArch(46,18,'232,201,106');}
function svgAnk(rx,ry,col){return'<svg viewBox="0 0 80 60" fill="none"><ellipse cx="40" cy="30" rx="'+rx+'" ry="'+ry+'" fill="rgba('+col+',.1)" stroke="rgba('+col+',.55)" stroke-width="1.5"/><line x1="'+(40-rx)+'" y1="30" x2="'+(40+rx)+'" y2="30" stroke="rgba('+col+',.18)" stroke-width="1" stroke-dasharray="3,2"/></svg>';}
function svgAnk1(){return svgAnk(11,18,'168,207,224');}function svgAnk2(){return svgAnk(16,20,'168,207,224');}function svgAnk3(){return svgAnk(22,23,'232,201,106');}
function svgCalf(d,col){return'<svg viewBox="0 0 80 60" fill="none"><path d="'+d+'" fill="rgba('+col+',.09)" stroke="rgba('+col+',.55)" stroke-width="1.5" stroke-linejoin="round"/></svg>';}
function svgC1(){return svgCalf('M31 53 Q23 39 25 23 Q27 9 40 7 Q53 9 55 23 Q57 39 49 53Z','168,207,224');}
function svgC2(){return svgCalf('M25 53 Q15 37 17 21 Q19 7 40 5 Q61 7 63 21 Q65 37 55 53Z','168,207,224');}
function svgC3(){return svgCalf('M17 53 Q5 35 7 17 Q9 3 40 1 Q71 3 73 17 Q75 35 63 53Z','232,201,106');}
var SVGS={ff1:svgFF1,ff2:svgFF2,ff3:svgFF3,ff4:svgFF4,a1:svgA1,a2:svgA2,a3:svgA3,ank1:svgAnk1,ank2:svgAnk2,ank3:svgAnk3,c1:svgC1,c2:svgC2,c3:svgC3};

var QS=[
  {id:'boot',sec:'Your Shell',lbl:'Boot Selection',txt:'What ski boot shell are you fitting?',hint:'Select brand, then filter by flex to narrow the model list.',type:'boot'},
  {id:'ff',sec:'Your Foot',lbl:'Forefoot Width',txt:'How wide is your forefoot?',hint:'Think about the widest part across the ball of your foot. All ZipFit liners accommodate a full range of forefoot widths — this helps us understand your foot better.',type:'anat',cols:'f4',scored:false,opts:[{s:'ff1',l:'Narrow',d:'Shoes feel too wide',v:'narrow'},{s:'ff2',l:'Medium',d:'Standard width fits right',v:'medium'},{s:'ff3',l:'Wide',d:'Standard shoes feel snug',v:'wide'},{s:'ff4',l:'Very Wide',d:'Always need wide sizing',v:'vwide'}]},
  {id:'ins',sec:'Your Foot',lbl:'Arch Height',txt:'How high is your arch?',hint:'Wet your foot and step on cardboard. A full footprint with little curve on the inside = flat/low arch. A footprint with a moderate indent = medium. A footprint with a very thin strip or big gap in the middle = high arch.',type:'anat',cols:'f3',scored:false,opts:[{s:'a1',l:'Low / Flat',d:'Full footprint, foot rolls inward',v:'low'},{s:'a2',l:'Medium',d:'Moderate arch, normal footprint',v:'medium'},{s:'a3',l:'High',d:'Distinct arch, thin strip on paper',v:'high'}]},
  {id:'ank',sec:'Your Foot',lbl:'Ankle Volume',txt:'How much volume does your ankle have?',sub:'Grab a soft tape measure for the best result.',hint:'Measure with a soft tape from one side of your heel to the other (around the back). If this is less than your foot length = small ankle. Equal to your foot length = average ankle. More than your foot length = large ankle.',type:'anat',cols:'f3',scored:true,opts:[{s:'ank1',l:'Bony / Lean',d:'Prominent bones, lean profile',v:'low'},{s:'ank2',l:'Average',d:'Moderate tissue around ankle',v:'medium'},{s:'ank3',l:'Full / Fleshy',d:'Lots of soft tissue at ankle',v:'high'}]},
  {id:'cal',sec:'Your Foot',lbl:'Calf and Lower Leg',txt:'How would you describe your calf and lower leg?',sub:'Grab a soft tape measure for the best result.',hint:'Measure your foot length in cm and add 10cm — that is your average calf benchmark. Measure your calf circumference at the widest point. Within 2cm either side of that number = average. More than 2cm above = full / muscular. More than 2cm below = lean / narrow.',type:'anat',cols:'f3',scored:true,opts:[{s:'c1',l:'Lean / Narrow',d:'Slim lower leg',v:'low'},{s:'c2',l:'Medium',d:'Average calf muscle',v:'medium'},{s:'c3',l:'Full / Muscular',d:'Developed calf, full lower leg',v:'high'}]},
  {id:'fit_problem',sec:'Your Foot',lbl:'Fit Challenges',txt:'Do you have any common fit problems?',hint:'This will not change your liner recommendation — we just want to make sure you know your liner will help, and point you to the right resources.',type:'choice',scored:false,opts:[
    {ic:'🦶',l:'Heel lift',d:'My heel moves or lifts inside the boot',v:'heel_lift'},
    {ic:'🦵',l:'Shin bang',d:'Pain on my shin while skiing',v:'shin_bang'},
    {ic:'💥',l:'Toe bang',d:'My toes hit the front of the boot',v:'toe_bang'},
    {ic:'↕️',l:'Navicular / instep pain',d:'Pain on the top of my foot or over the arch',v:'navicular_pain'},
    {ic:'🥶',l:'Cold feet',d:'My feet get uncomfortably cold',v:'cold_feet'},
    {ic:'↔️',l:'Wide forefoot pressure',d:'Pain or pressure across the ball of my foot',v:'wide_forefoot'},
    {ic:'🦴',l:'Ankle bite',d:'Pain on the sides of my ankles',v:'ankle_bite'},
    {ic:'✓',l:'No major issues',d:'My current fit is generally comfortable',v:'none'}
  ]},
  {id:'terrain',sec:'Your Skiing',lbl:'Where You Ski',txt:'Where do you spend most of your time on the mountain?',hint:'Select all that apply.',type:'choice',multi:true,scored:false,opts:[
    {ic:'🏔️',l:'All Mountain',d:'Mix of groomers, off-piste, and variable conditions',v:'all_mountain'},
    {ic:'🎿',l:'Carving',d:'Mostly groomed runs, focused on edge-to-edge performance',v:'carving'},
    {ic:'🛹',l:'Park',d:'Freestyle, features, and terrain park laps',v:'park'},
    {ic:'🧭',l:'Touring',d:'Backcountry touring or lift-accessed sidecountry',v:'touring'},
  ]},
  {id:'touring_primary',sec:'Your Skiing',lbl:'Touring Focus',txt:'Do you spend most of your ski days touring?',hint:'This helps us prioritize liners built for uphill performance and low weight.',type:'choice',scored:false,opts:[
    {ic:'✅',l:'Yes — mainly touring',d:'The majority of my ski days involve skinning up',v:'yes'},
    {ic:'⛷️',l:'No — touring occasionally',d:'I tour some days but mostly ski resort or sidecountry',v:'no'},
  ]},
  {id:'ability',sec:'Your Skiing',lbl:'Ability Level',txt:'How would you describe your skiing ability?',hint:'Be honest — there is a perfect liner for every level.',type:'choice',scored:true,opts:[{ic:'🎿',l:'Beginner',d:'Learning the basics',v:1},{ic:'⛷️',l:'Intermediate',d:'Comfortable on most trails',v:2},{ic:'🏔️',l:'Advanced',d:'Confident in all conditions',v:3},{ic:'🏁',l:'Expert',d:'Aggressive, max performance',v:4}]},
];

var step=0,ans={},sliders={};
var sBrand='',sFlex='',sModel='',sBoot=null;

function vtc(v){if(!v||v==='nan')return'';if(v.indexOf('Race')>-1)return'rc';if(v==='LV')return'lv';if(v==='HV'||v==='EHV')return'hv';return'mv';}
function findBoots(brand,model){var r=[];for(var i=0;i<BOOTS.length;i++){if(BOOTS[i].b===brand&&BOOTS[i].m===model)r.push(BOOTS[i]);}return r;}

function buildPicker(){
  var bOpts='<option value="">Select brand...</option>';
  for(var i=0;i<BRANDS.length;i++){bOpts+='<option value="'+BRANDS[i]+'"'+(sBrand===BRANDS[i]?' selected':'')+'>'+BRANDS[i]+'</option>';}
  var fOpts='<option value="">All flex ratings</option>';
  var fDis=!sBrand;
  if(sBrand&&BF[sBrand]){var fxs=BF[sBrand];for(var j=0;j<fxs.length;j++){fOpts+='<option value="'+fxs[j]+'"'+(sFlex===String(fxs[j])?' selected':'')+'>'+fxs[j]+'</option>';}}
  var mOpts='<option value="">Select model...</option>';
  var mDis=!sBrand;
  var models=[];
  if(sBrand&&BFM[sBrand]){
    if(sFlex&&BFM[sBrand][sFlex]){models=BFM[sBrand][sFlex];}
    else if(!sFlex){var seen={},allK=Object.keys(BFM[sBrand]);for(var k=0;k<allK.length;k++){var ms=BFM[sBrand][allK[k]];for(var m=0;m<ms.length;m++){if(!seen[ms[m]]){seen[ms[m]]=1;models.push(ms[m]);}}}models.sort();}
  }
  for(var n=0;n<models.length;n++){mOpts+='<option value="'+models[n]+'"'+(sModel===models[n]?' selected':'')+'>'+models[n]+'</option>';}
  var matches=sModel?findBoots(sBrand,sModel):[];
  var needYear=matches.length>1;
  var selYear=sBoot?sBoot.y:'';
  var yOpts='<option value="">Select year...</option>';
  if(needYear){for(var p=0;p<matches.length;p++){yOpts+='<option value="'+matches[p].y+'"'+(selYear===matches[p].y?' selected':'')+'>'+matches[p].y+'</option>';}}
  if(matches.length===1&&!sBoot){sBoot=matches[0];ans.boot=sBoot;}
  var card='';
  if(sBoot){
    var vc=vtc(sBoot.v);
    var vt=sBoot.v&&sBoot.v!=='nan'?'<span class="tg '+vc+'">'+sBoot.v+'</span>':'';
    var ft=sBoot.f?'<span class="tg yr">'+sBoot.f+'</span>':'';
    var lt=sBoot.l?'<span class="tg yr">'+sBoot.l+'mm</span>':'';
    var wt=sBoot.w?'<span class="tg tr">Tour</span>':'';
    card='<div class="boot-card"><div><div class="bc-m">'+sBoot.m+'</div><div class="bc-x">'+sBoot.b+' &middot; '+sBoot.y+'</div><div class="bc-tags">'+vt+lt+ft+wt+'</div></div><button class="bc-chg" id="bc-clr">Change</button></div>';
  }
  var stTxt=sBoot?'&#10003; Boot confirmed':needYear&&sModel?'Select year to confirm':sModel?'Confirming...':sBrand?'Now select a model':'Start by choosing your brand';
  var stCls=sBoot?' ok':'';
  return '<div class="picker">'+card
    +'<div class="drop-row tri">'
    +'<div class="dg"><div class="dl">Brand</div><select class="ds" id="dp-b">'+bOpts+'</select></div>'
    +'<div class="dg"><div class="dl">Flex <em>optional filter</em></div><select class="ds" id="dp-f"'+(fDis?' disabled':'')+'>'+fOpts+'</select></div>'
    +'<div class="dg"><div class="dl">Model</div><select class="ds" id="dp-m"'+(mDis?' disabled':'')+'>'+mOpts+'</select></div>'
    +'</div>'
    +(needYear
      ?'<div class="drop-row"><div class="dg"><div class="dl">Year <em>specs differ by year</em></div><select class="ds" id="dp-y">'+yOpts+'</select></div><div class="dg" style="justify-content:flex-end;padding-top:22px"><div class="status'+stCls+'">'+stTxt+'</div></div></div>'
      :'<div class="status'+stCls+'" style="padding:6px 2px 2px">'+stTxt+'</div>'
    )+'</div>';
}

function attachPicker(){
  var dpb=document.getElementById('dp-b');if(dpb)dpb.addEventListener('change',function(){sBrand=this.value;sFlex='';sModel='';sBoot=null;ans.boot=undefined;repick();});
  var dpf=document.getElementById('dp-f');if(dpf)dpf.addEventListener('change',function(){sFlex=this.value;sModel='';sBoot=null;ans.boot=undefined;repick();});
  var dpm=document.getElementById('dp-m');if(dpm)dpm.addEventListener('change',function(){sModel=this.value;sBoot=null;ans.boot=undefined;repick();setTimeout(function(){if(sBoot){var nx=document.getElementById('nx');if(nx)nx.removeAttribute('disabled');setTimeout(goNext,400);}},60);});
  var dpy=document.getElementById('dp-y');if(dpy)dpy.addEventListener('change',function(){var yr=this.value;if(yr){var ms=findBoots(sBrand,sModel);for(var i=0;i<ms.length;i++){if(ms[i].y===yr){sBoot=ms[i];break;}}ans.boot=sBoot||undefined;}else{sBoot=null;ans.boot=undefined;}repick();if(sBoot)setTimeout(goNext,400);});
  var clr=document.getElementById('bc-clr');if(clr)clr.addEventListener('click',function(){sBrand='';sFlex='';sModel='';sBoot=null;ans.boot=undefined;repick();});
  var nx=document.getElementById('nx');if(nx){if(sBoot)nx.removeAttribute('disabled');else nx.setAttribute('disabled','');}
}
function repick(){var w=document.getElementById('picker-wrap');if(w){w.innerHTML=buildPicker();attachPicker();}}

function pct(){return Math.round((step/QS.length)*100);}
function secDiv(i){if(i===0||QS[i].sec!==QS[i-1].sec)return'<div class="sec"><span>'+QS[i].sec+'</span></div>';return'';}

function render(){
  var w=document.getElementById('quiz');
  if(step>=QS.length){showResult(w);return;}
  var q=QS[step],a=ans[q.id],body='';
  if(q.type==='boot'){
    body='<div id="picker-wrap">'+buildPicker()+'</div>';
  }else if(q.type==='anat'){
    body='<div class="ag '+q.cols+'">';
    for(var i=0;i<q.opts.length;i++){var o=q.opts[i];var s=SVGS[o.s]?SVGS[o.s]():'';body+='<button class="ao'+(a===o.v?' on':'')+'" data-v="'+o.v+'" data-q="'+q.id+'"><div class="svg-wrap">'+s+'</div><div class="al">'+o.l+'</div><div class="ad">'+o.d+'</div></button>';}
    body+='</div>';
  }else if(q.type==='choice'){
    body='<div class="cg">';
    for(var i=0;i<q.opts.length;i++){var o=q.opts[i];body+='<button class="co'+(a===o.v?' on':'')+'" data-v="'+o.v+'" data-q="'+q.id+'"><span class="ci">'+o.ic+'</span><span><div class="cl">'+o.l+'</div><div class="cd2">'+o.d+'</div></span></button>';}
    body+='</div>';
  }else if(q.type==='slider'){
    var v=sliders[q.id]||q.def,labs=['','Not at all','A little','Moderate','Important','Critical'];
    body='<div class="slw"><div class="sll"><span>'+q.minL+'</span><span>'+q.maxL+'</span></div><input type="range" id="sl" min="'+q.min+'" max="'+q.max+'" value="'+v+'"><div class="slv" id="sv">'+labs[v]+'<span>'+v+' / 5</span></div></div>';
  }
  var ok=q.type==='slider'||(q.type==='boot'&&sBoot)||a!==undefined;
  w.innerHTML=
    '<div class="prog"><div class="prog-top"><b>Step '+(step+1)+' of '+QS.length+'</b><span>'+q.lbl+'</span></div><div class="prog-track"><div class="prog-bar" style="width:'+pct()+'%"></div></div></div>'
    +'<div class="card">'+secDiv(step)
    +'<div class="qn">Question '+(step+1)+'</div><div class="qt">'+q.txt+'</div><div class="qh">'+q.hint+'</div>'+(q.sub?'<div class="qsub">'+q.sub+'</div>':'')
    +body
    +'<div class="nav">'+(step>0?'<button class="nbk" id="bk">&#8592; Back</button>':'<span></span>')
    +'<button class="nxt" id="nx"'+(ok?'':' disabled')+'>'+(step===QS.length-1?'See My Liner &#8594;':'Next &#8594;')+'</button></div></div>'
    +'<p class="disc">Starting point only. A certified bootfitter provides the definitive fit.</p>';
  if(q.type==='boot')attachPicker();
  w.querySelectorAll('.ao,.co').forEach(function(b){b.addEventListener('click',function(){pick(this.dataset.q,this.dataset.v);});});
  var sl=document.getElementById('sl');if(sl)sl.addEventListener('input',function(){var v=this.value,labs=['','Not at all','A little','Moderate','Important','Critical'];sliders[q.id]=parseInt(v);ans[q.id]=parseInt(v);var el=document.getElementById('sv');if(el)el.innerHTML=labs[v]+'<span>'+v+' / 5</span>';});
  document.getElementById('nx').addEventListener('click',goNext);
  var bk=document.getElementById('bk');if(bk)bk.addEventListener('click',goBack);
}

function pick(qid,val){
  var n=parseFloat(val);
  ans[qid]=isNaN(n)?val:n;
  render();
  // fit_problem and forefoot don't auto-advance — let user confirm manually
  var q=QS[step];
  if(q&&q.scored!==false)setTimeout(goNext,280);
}
function goNext(){
  var q=QS[step];
  if(q.type==='slider')ans[q.id]=sliders[q.id]||q.def;
  if(q.type==='boot'&&!sBoot)return;
  if(ans[q.id]===undefined&&q.type!=='slider'&&q.type!=='boot')return;
  step++;render();window.scrollTo({top:0,behavior:'smooth'});
}
function goBack(){if(step>0){step--;render();window.scrollTo({top:0,behavior:'smooth'});}}

function scoreLiners(){
  var boot=ans.boot||{},vol=boot.v||'MV',last=boot.l||0;
  // True only when the user has a walk-mode boot AND confirmed touring is their primary use.
  var terrainArr=Array.isArray(ans.terrain)?ans.terrain:(ans.terrain?[ans.terrain]:[]);
  var isTourPrimary=!!(boot.w&&terrainArr.indexOf('touring')>-1&&ans.touring_primary==='yes');
  return LINERS.map(function(l){
    var s=0;
    // TIER 1 — SHELL GATES (dominant, ensures right liner wins for the shell)
    // Corsa: race shells <=94mm only — penalty when touring is primary use
    if(l.id==='corsa'){if(last===0||last>94)return{l:l,s:-999};if(isTourPrimary)s-=80;s+=100;}
    // Espresso: ultralight LV touring — only when touring is primary use
    if(l.id==='espresso'){
      var isUL=isTourPrimary&&last>0&&last<=98&&(vol==='LV'||vol==='Race/LV'||vol==='Race');
      if(!isUL)return{l:l,s:-999};s+=92;
    }
    // GFT: 96mm DH or strong boost when touring is primary use
    if(l.id==='gft'){
      var isDH=!boot.w&&last===96;
      var isTour=isTourPrimary&&last>0&&last>=96;
      if(isDH)s+=90;else if(isTour)s+=88;
    }
    // Gara LV: 96-100mm, lean/avg calf — penalty when touring is primary use
    // Full/fleshy ankle → LV (natural tissue already fills the shell; LV liner fits precisely)
    // Flat arch + lean ankle together → HV (compound signal overrides; lean alone → mild LV pull)
    if(l.id==='gara_lv'){
      if(last===0||last<96||last>100)return{l:l,s:-999};
      if(isTourPrimary)s-=80;
      if(ans.cal==='high')return{l:l,s:-999};
      s+=95;
      if(ans.ank==='high')s+=30;
      else if(ans.ank==='low'&&ans.ins==='low')s-=30;
      else if(ans.ank==='low')s+=15;
    }
    // Gara HV: 100-104mm, lean/avg calf — penalty when touring is primary use
    // Full/fleshy ankle → not HV (adding liner bulk over existing tissue overfills the shell)
    // Flat arch + lean ankle → HV (dead space from both signals; liner fill is needed)
    if(l.id==='gara_hv'){
      if(last===0||last<100||last>104)return{l:l,s:-999};
      if(isTourPrimary)s-=80;
      if(ans.cal==='high')return{l:l,s:-999};
      s+=95;
      if(ans.ank==='high')s-=30;
      else if(ans.ank==='low'&&ans.ins==='low')s+=30;
      else if(ans.ank==='low')s-=10;
    }
    // Freeride: 100-106mm, +30 large calf, +12 when touring is primary use
    if(l.id==='freeride'){
      if(last>0&&(last<100||last>106))return{l:l,s:-999};
      s+=70;
      if(ans.cal==='high')s+=30;
      if(isTourPrimary)s+=12;
    }
    // Workhorse: 100-106mm, expert only
    if(l.id==='workhorse'){
      if(last>0&&(last<100||last>106))return{l:l,s:-999};
      if(!ans.ability||ans.ability<4)return{l:l,s:-999};
      s+=70;
    }
    // TIER 2 — SHELL VOLUME MATCH (secondary ~30pts)
    if(l.vols.indexOf(vol)>-1)s+=30;
    else if(vol==='HV'&&l.vols.indexOf('MV')>-1)s+=10;
    else if(vol==='MV'&&l.vols.indexOf('LV')>-1)s+=5;
    // TIER 3 — FOOT SHAPE REFINEMENT (tie-breaker, max 52pts)
    if(ans.ins&&l.ins.indexOf(ans.ins)>-1)s+=10;
    if(ans.ank&&l.ank.indexOf(ans.ank)>-1)s+=26;
    if(ans.cal&&l.cal.indexOf(ans.cal)>-1)s+=16;
    // TIER 4 — ABILITY (max 20pts)
    var ab=ans.ability||2;
    if(ab>=4&&l.p>=5)s+=20;else if(ab>=3&&l.p>=4)s+=14;else if(ab<=2&&l.w>=3)s+=12;
    return{l:l,s:s};
  }).sort(function(a,b){return b.s-a.s;});
}
var FL={ff:{narrow:'Narrow',medium:'Medium',wide:'Wide',vwide:'Very Wide'},ins:{low:'Low / Flat',medium:'Medium',high:'High'},ank:{low:'Bony / Lean',medium:'Average',high:'Full / Fleshy'},cal:{low:'Lean / Narrow',medium:'Medium',high:'Full / Muscular'}};
function esc(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}

function showResult(w){
  var ranked=scoreLiners();
  // Filter out hard-excluded liners for alt suggestions
  var valid=ranked.filter(function(r){return r.s>-900;});
  var top=valid[0].l,alts=valid.slice(1,3).map(function(r){return r.l;});
  var boot=ans.boot||{};
  var bc={LV:'var(--gl)',HV:'var(--gl2)',Race:'#f0a0a0'}[boot.v]||'var(--gl)';

  // Foot profile rows — forefoot included for display
  var ffLabel={narrow:'Narrow',medium:'Medium',wide:'Wide',vwide:'Very Wide'};
  var fRows=[
    {l:'Forefoot Width',v:ffLabel[ans.ff]},
    {l:'Navicular / Instep',v:FL.ins[ans.ins]},
    {l:'Ankle Volume',v:FL.ank[ans.ank]},
    {l:'Calf Volume',v:FL.cal[ans.cal]}
  ].filter(function(r){return r.v;});

  // Fit problem card
  var fpData=null;
  if(ans.fit_problem&&ans.fit_problem!=='none'){
    for(var i=0;i<FIT_PROBLEMS.length;i++){if(FIT_PROBLEMS[i].v===ans.fit_problem){fpData=FIT_PROBLEMS[i];break;}}
  }

  var fs={'Low':'Precision Race','Low-Medium':'Performance','Medium':'All-Day','Medium-High':'Comfort-Forward','High':'Maximum Warmth'};

  w.innerHTML='<div class="card" style="animation:up .5s ease">'
    +'<div class="rh"><div class="re">Your ZipFit Match</div><div class="rt">ZipFit '+top.name+'</div><p class="rg">'+top.tag+'</p><div class="rb">Recommended Liner</div></div>'

    // Shell card
    +(boot.m?'<div class="ib sh"><h3>Shell: '+esc(boot.b)+' '+esc(boot.m)+'</h3><div class="ig"><div class="ic"><div class="il">Last</div><div class="iv" style="color:'+bc+'">'+(boot.l||'&#8212;')+'mm</div></div><div class="ic"><div class="il">Volume</div><div class="iv">'+(boot.v&&boot.v!=='nan'?boot.v:'&#8212;')+'</div></div><div class="ic"><div class="il">Flex</div><div class="iv">'+(boot.f||'&#8212;')+'</div></div><div class="ic"><div class="il">Year</div><div class="iv">'+boot.y+'</div></div><div class="ic"><div class="il">Walk Mode</div><div class="iv">'+(boot.w?'Yes':'No')+'</div></div><div class="ic"><div class="il">Brand</div><div class="iv">'+esc(boot.b)+'</div></div></div></div>':'')

    // Foot profile card
    +(fRows.length?'<div class="ib ft"><h3>Your Foot Profile</h3><div class="fg2">'+fRows.map(function(r){return'<div class="ic"><div class="il">'+r.l+'</div><div class="iv">'+r.v+'</div></div>';}).join('')+'</div></div>':'')

    // Fit problem reassurance card
    +(fpData?'<div class="ib fp"><h3>'+fpData.icon+' About your '+fpData.l.toLowerCase()+'</h3><p class="fp-msg">'+fpData.msg+'</p>'+(fpData.link?'<a class="fp-link" href="'+fpData.link+'">&#10142; Solutions for '+fpData.l.toLowerCase()+'</a>':'')+'</div>':'')

    // Liner stats
    +'<div class="rg2"><div class="rs"><div class="sl2">Performance</div><div class="bb"><div class="bf" style="width:0%;background:linear-gradient(90deg,#a8cfe0,#c9a84c)" data-w="'+(top.p*20)+'%"></div></div></div><div class="rs"><div class="sl2">Warmth</div><div class="bb"><div class="bf" style="width:0%;background:linear-gradient(90deg,#c9a84c,#e8c96a)" data-w="'+(top.w*20)+'%"></div></div></div><div class="rs"><div class="sl2">Volume</div><div class="sv2">'+top.vol+'</div></div><div class="rs"><div class="sl2">Fit Style</div><div class="sv2">'+(fs[top.vol]||top.vol)+'</div></div></div>'

    +'<div class="wb"><h3>Why this liner for you</h3><p>'+top.why+'</p></div>'
    +'<div class="sl2" style="margin-bottom:8px">Key Features</div><div class="tgs">'+top.feat.map(function(f){return'<span class="ftg">'+f+'</span>';}).join('')+'</div>'
    +'<div class="ab"><div class="abl">Also Consider</div>'+alts.map(function(a){return'<div class="ai"><div class="an">ZipFit '+a.name+'</div><div class="ax">'+a.tag+'</div></div>';}).join('')+'</div>'
    +'<button class="restart" id="rs">&#8635; Retake the Quiz</button></div>'
    +'<p class="disc">A certified ZipFit bootfitter provides the definitive professional fit.</p>';

  document.getElementById('rs').addEventListener('click',restart);
  setTimeout(function(){document.querySelectorAll('.bf[data-w]').forEach(function(e){e.style.width=e.getAttribute('data-w');});},100);
}

